import{_ as d,o as a,c as s,ag as n}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"表情标签配置","description":"","frontmatter":{"title":"表情标签配置"},"headers":[],"relativePath":"app-config/emotion-tags.md","filePath":"app-config/emotion-tags.md","lastUpdated":null}'),e={name:"app-config/emotion-tags.md"};function r(p,t,l,i,o,c){return a(),s("div",null,[...t[0]||(t[0]=[n(`<p>表情标签配置说明</p><p>除了文字与语音播报，AIUI极速超拟人交互系统还提供了丰富的表情表达，**表情标签 (Facial Expression)**代表了 AI 回复时的情绪与内心状态，让开发者和用户能够感知到 AI 的“心情”与“意图”，从而为产品带来拟人灵动的交互体验。目前表情的颗粒度是会话级别的，即一轮AI回复带一个表情标签。</p><p>注意：该能力只能在<strong>极速超拟人交互链路</strong>下开启使用。</p><h1 id="表情标签的用途" tabindex="-1">表情标签的用途 <a class="header-anchor" href="#表情标签的用途" aria-label="Permalink to &quot;表情标签的用途&quot;">​</a></h1><ul><li>增强聊天沉浸感：在聊天气泡旁展示对应的 Emoji，根据情绪改变交互界面设计，让对话更有温度。</li><li>驱动面部表情：通过读取表情标签，可以让您的2D、3D 虚拟形象或机器人面部实时做出对应的表情（如大笑、哭泣、害羞），实现音容笑貌同步。</li><li>情绪分析统计：后台可以统计用户与 AI 交互过程中的情绪变化趋势，分析对话质量。</li></ul><h1 id="表情列表" tabindex="-1">表情列表 <a class="header-anchor" href="#表情列表" aria-label="Permalink to &quot;表情列表&quot;">​</a></h1><p>AIUI当前支持25个表情标签，清单如下所示。</p><table tabindex="0"><thead><tr><th>emoji（中性）</th><th>情绪类型</th><th>描述</th></tr></thead><tbody><tr><td></td><td>neutral</td><td>中性、平静</td></tr><tr><td></td><td>embarrassed</td><td>尴尬、害羞</td></tr><tr><td></td><td>surprised</td><td>惊讶</td></tr><tr><td></td><td>thinking</td><td>思考、疑惑</td></tr><tr><td></td><td>sleepy</td><td>困倦、疲惫</td></tr><tr><td></td><td>comfort</td><td>安慰</td></tr><tr><td></td><td>pleading</td><td>撒娇、恳求</td></tr></tbody></table><table tabindex="0"><thead><tr><th>emoji（正面）</th><th>情绪类型</th><th>描述</th></tr></thead><tbody><tr><td></td><td>happy</td><td>开心，幸福，满足、元气</td></tr><tr><td></td><td>cheerful</td><td>大笑</td></tr><tr><td></td><td>tears_of_joy</td><td>笑哭</td></tr><tr><td></td><td>loving</td><td>喜爱</td></tr><tr><td></td><td>cool</td><td>酷</td></tr><tr><td></td><td>relax</td><td>放松</td></tr><tr><td></td><td>drool</td><td>馋</td></tr><tr><td></td><td>blow_a_kiss</td><td>飞吻</td></tr><tr><td></td><td>congratulate</td><td>庆祝、祝贺</td></tr><tr><td></td><td>playful</td><td>调皮的</td></tr><tr><td></td><td>silly_ghost</td><td>搞怪</td></tr></tbody></table><table tabindex="0"><thead><tr><th>emoji（负面）</th><th>情绪类型</th><th>描述</th></tr></thead><tbody><tr><td></td><td>angry</td><td>愤怒</td></tr><tr><td></td><td>sad</td><td>悲伤、失望</td></tr><tr><td></td><td>sigh</td><td>叹息、无奈</td></tr><tr><td></td><td>crying</td><td>哭泣、难过</td></tr><tr><td></td><td>unlucky</td><td>衰、倒霉</td></tr><tr><td></td><td>anxiety</td><td>焦虑、恐惧</td></tr><tr><td></td><td>sorry</td><td>对不起</td></tr></tbody></table><p>（按情绪类型分类，表情包图片衍生自<a href="https://js.design/community?category=detail&amp;type=resource&amp;id=63fdfc8794031f91575c6629" title="【BIGD】轻拟物表情设计" target="_blank" rel="noreferrer">【BIGD】轻拟物表情设计</a>｜CC BY 4.0）</p><h1 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h1><p>如果您想申请接入表情驱动能力，请联系商务/技术支持获得授权。获得授权后，只需要在应用配置下打开表情驱动，即可获得云端下发的表情结果。下发数据结构示例：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>&#39;cbm_facial_expression&#39;: {</span></span>
<span class="line"><span>    &#39;compress&#39;: &#39;raw&#39;,</span></span>
<span class="line"><span>    &#39;encoding&#39;: &#39;utf8&#39;,</span></span>
<span class="line"><span>    &#39;format&#39;: &#39;plain&#39;,</span></span>
<span class="line"><span>    &#39;seq&#39;: 0,</span></span>
<span class="line"><span>    &#39;status&#39;: 2,</span></span>
<span class="line"><span>    &#39;text&#39;: &#39;happy&#39;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div>`,14)])])}const m=d(e,[["render",r]]);export{b as __pageData,m as default};
